import { createSlice } from '@reduxjs/toolkit'

const userSlice = createSlice({
    name: 'user',
    initialState: {
        currentUser: null,
        loading: false,
        error: false
    },
    reducers: {
        loginStart: (state) => {
            state.currentUser = null
            state.loading = true
            state.error = false
        },
        loginSuccess: (state, action) => {
            state.currentUser = action.payload
            state.loading = false
            state.error = false
        },
        loginFailure: (state, action) => {
            state.loading = false
            state.error = true
        },
        logout: (state) => {
            state.currentUser = null
            state.loading = false
            state.error = false
        }
    }
})

export const {
    loginStart,
    loginSuccess,
    loginFailure,
    logout
} = userSlice.actions
export default userSlice.reducer