import { useEffect, useState } from 'react'
import { useSelector } from 'react-redux'
import { useLocation, useNavigate } from 'react-router-dom'
import { 
  Container, Typography, Box, Paper, Grid, Chip, Button, 
  Divider, Card, CardContent, IconButton, Menu, MenuItem,
  Dialog, DialogTitle, DialogContent, DialogActions, TextField,
  Select, FormControl, InputLabel, Stack, CircularProgress, 
  Avatar, Alert, Snackbar, OutlinedInput
} from '@mui/material'
import Navbar from '../components/Navbar'
import {
  Add as AddIcon,
  MoreVert as MoreVertIcon,
  Schedule as ScheduleIcon,
  Person as PersonIcon,
  Flag as FlagIcon,
  ArrowBack as ArrowBackIcon,
  PersonAdd as PersonAddIcon
} from '@mui/icons-material'
import Footer from '../components/Footer'
import { userRequest } from '../requestMethods'

const Project = () => {
  const navigate = useNavigate()
  const location = useLocation()
  const projectId = location.pathname.split('/')[2]
  const { currentUser } = useSelector(state => state.user)
  
  // State for project data
  const [project, setProject] = useState(null)
  const [tasks, setTasks] = useState([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState('')

  // Check if current user is project admin
  const isProjectAdmin = project?.members?.find(
    m => (typeof m.user === 'object' ? m.user._id : m.user) === currentUser?._id
  )?.role === 'admin'

  // Group tasks by status
  const todoTasks = tasks.filter(task => task.status === 'todo')
  const inProgressTasks = tasks.filter(task => task.status === 'in_progress')
  const reviewTasks = tasks.filter(task => task.status === 'review')
  const doneTasks = tasks.filter(task => task.status === 'done')

  // State for task detail dialog
  const [selectedTask, setSelectedTask] = useState(null)
  const [taskDialogOpen, setTaskDialogOpen] = useState(false)
  
  // State for create task dialog
  const [createTaskOpen, setCreateTaskOpen] = useState(false)
  const [newTask, setNewTask] = useState({
    title: '',
    description: '',
    priority: 'medium',
    assignedTo: '',
    dueDate: ''
  })

  // State for member management
  const [memberDialogOpen, setMemberDialogOpen] = useState(false)
  const [availableUsers, setAvailableUsers] = useState([])
  const [selectedUsers, setSelectedUsers] = useState([])
  const [snackbar, setSnackbar] = useState({ open: false, message: '', severity: 'success' })

  // State for anchor menu
  const [anchorEl, setAnchorEl] = useState(null)
  const [menuTaskId, setMenuTaskId] = useState(null)

  // Fetch project and tasks
  useEffect(() => {
    const fetchProject = async () => {
      try {
        setLoading(true)
        const res = await userRequest.get(`/projects/${projectId}`)
        setProject(res.data.project)
        setTasks(res.data.tasks || [])
      } catch (err) {
        console.error('Error fetching project:', err)
        setError(err.response?.data?.message || 'Failed to load project')
      } finally {
        setLoading(false)
      }
    }
    fetchProject()
  }, [projectId])

  // Check if user can move task
  const canMoveTask = (task) => {
    if (!currentUser) return false
    
    const isAssignedTo = typeof task.assignedTo === 'object' 
      ? task.assignedTo?._id === currentUser._id 
      : task.assignedTo === currentUser._id
    
    const isCreator = typeof task.createdBy === 'object'
      ? task.createdBy?._id === currentUser._id
      : task.createdBy === currentUser._id
    
    return isProjectAdmin || isAssignedTo || isCreator
  }

  // Handle task click
  const handleTaskClick = (task) => {
    setSelectedTask(task)
    setTaskDialogOpen(true)
  }

  // Handle menu open
  const handleMenuOpen = (event, taskId) => {
    event.stopPropagation()
    
    // Check if user can manage this task
    const task = tasks.find(t => t._id === taskId)
    if (task && !canMoveTask(task)) {
      setSnackbar({
        open: true,
        message: 'Only admin, task creator, or assigned user can move this task',
        severity: 'warning'
      })
      return
    }
    
    setAnchorEl(event.currentTarget)
    setMenuTaskId(taskId)
  }

  // Handle menu close
  const handleMenuClose = () => {
    setAnchorEl(null)
    setMenuTaskId(null)
  }

  // Handle status change
  const handleStatusChange = async (taskId, newStatus) => {
    try {
      await userRequest.patch(`/tasks/task/${taskId}/status`, { status: newStatus })
      
      // Update local state
      setTasks(tasks.map(task => 
        task._id === taskId ? { ...task, status: newStatus } : task
      ))
      
      setSnackbar({
        open: true,
        message: `Task moved to ${newStatus.replace('_', ' ')}`,
        severity: 'success'
      })
      
      handleMenuClose()
    } catch (err) {
      setSnackbar({
        open: true,
        message: err.response?.data?.message || 'Failed to update task',
        severity: 'error'
      })
    }
  }

  // Handle create task
  const handleCreateTask = async () => {
    try {
      const res = await userRequest.post(`/tasks/${projectId}`, newTask)
      
      // Add new task to local state
      setTasks([...tasks, res.data])
      
      setCreateTaskOpen(false)
      setNewTask({
        title: '',
        description: '',
        priority: 'medium',
        assignedTo: '',
        dueDate: ''
      })
      
      setSnackbar({
        open: true,
        message: 'Task created successfully',
        severity: 'success'
      })
    } catch (err) {
      setSnackbar({
        open: true,
        message: err.response?.data?.message || 'Failed to create task',
        severity: 'error'
      })
    }
  }

  // Handle delete task
  const handleDeleteTask = async (taskId) => {
    try {
      await userRequest.delete(`/tasks/task/${taskId}`)
      
      // Remove task from local state
      setTasks(tasks.filter(task => task._id !== taskId))
      
      setSnackbar({
        open: true,
        message: 'Task deleted successfully',
        severity: 'success'
      })
      
      handleMenuClose()
    } catch (err) {
      setSnackbar({
        open: true,
        message: err.response?.data?.message || 'Failed to delete task',
        severity: 'error'
      })
    }
  }

  // Open member management dialog
  const handleOpenMemberDialog = async () => {
    try {
      const res = await userRequest.get('/users')
      setAvailableUsers(res.data)
      setMemberDialogOpen(true)
    } catch (err) {
      setSnackbar({
        open: true,
        message: 'Failed to fetch users',
        severity: 'error'
      })
    }
  }

  // Add members to project
  const handleAddMembers = async () => {
    try {
      const promises = selectedUsers.map(userId =>
        userRequest.post(`/projects/${projectId}/members`, {
          userId,
          role: 'member'
        })
      )
      
      await Promise.all(promises)
      
      // Refresh project data
      const res = await userRequest.get(`/projects/${projectId}`)
      setProject(res.data.project)
      
      setSelectedUsers([])
      setMemberDialogOpen(false)
      
      setSnackbar({
        open: true,
        message: 'Members added successfully',
        severity: 'success'
      })
    } catch (err) {
      setSnackbar({
        open: true,
        message: err.response?.data?.message || 'Failed to add members',
        severity: 'error'
      })
    }
  }

  // Remove member from project
  const handleRemoveMember = async (userId) => {
    try {
      await userRequest.delete(`/projects/${projectId}/members/${userId}`)
      
      // Refresh project data
      const res = await userRequest.get(`/projects/${projectId}`)
      setProject(res.data.project)
      
      setSnackbar({
        open: true,
        message: 'Member removed successfully',
        severity: 'success'
      })
    } catch (err) {
      setSnackbar({
        open: true,
        message: err.response?.data?.message || 'Failed to remove member',
        severity: 'error'
      })
    }
  }

  const getPriorityColor = (priority) => {
    switch(priority) {
      case 'high': return 'error'
      case 'medium': return 'warning'
      case 'low': return 'success'
      default: return 'default'
    }
  }

  const getStatusColor = (status) => {
    switch(status) {
      case 'todo': return 'info'
      case 'in_progress': return 'warning'
      case 'review': return 'secondary'
      case 'done': return 'success'
      default: return 'default'
    }
  }

  // Task Card Component
  const TaskCard = ({ task }) => (
    <Card
      elevation={1}
      sx={{
        mb: 1.5,
        cursor: 'pointer',
        transition: 'all 0.2s',
        borderLeft: 4,
        borderColor: `${getPriorityColor(task.priority)}.main`,
        opacity: canMoveTask(task) ? 1 : 0.9,
        '&:hover': {
          boxShadow: 3,
          transform: 'translateY(-2px)'
        }
      }}
    >
      <CardContent sx={{ p: 1.5, '&:last-child': { pb: 1.5 } }}>
        <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
          <Box sx={{ flex: 1 }} onClick={() => handleTaskClick(task)}>
            <Typography variant="subtitle2" sx={{ fontWeight: 600, mb: 0.5 }}>
              {task.title}
            </Typography>
            
            {task.description && (
              <Typography 
                variant="caption" 
                color="text.secondary"
                sx={{ 
                  display: '-webkit-box',
                  WebkitLineClamp: 2,
                  WebkitBoxOrient: 'vertical',
                  overflow: 'hidden',
                  mb: 1
                }}
              >
                {task.description}
              </Typography>
            )}
          </Box>
          
          <IconButton 
            size="small"
            onClick={(e) => handleMenuOpen(e, task._id)}
          >
            <MoreVertIcon fontSize="small" />
          </IconButton>
        </Box>

        <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, mt: 1 }}>
          {task.dueDate && (
            <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.5 }}>
              <ScheduleIcon sx={{ fontSize: 14, color: 'text.secondary' }} />
              <Typography variant="caption" color="text.secondary">
                {new Date(task.dueDate).toLocaleDateString('en-US', { 
                  month: 'short', 
                  day: 'numeric' 
                })}
              </Typography>
            </Box>
          )}
          
          <Chip
            icon={<FlagIcon />}
            label={task.priority}
            size="small"
            color={getPriorityColor(task.priority)}
            variant="outlined"
            sx={{ height: 20, fontSize: '0.7rem' }}
          />
        </Box>

        {task.assignedTo && (
          <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.5, mt: 0.5 }}>
            <PersonIcon sx={{ fontSize: 14, color: 'text.secondary' }} />
            <Typography variant="caption" color="text.secondary">
              {typeof task.assignedTo === 'object' 
                ? task.assignedTo.fullName 
                : 'Assigned'}
            </Typography>
          </Box>
        )}
      </CardContent>
    </Card>
  )

  if (loading) {
    return (
      <>
        <Navbar />
        <Container sx={{ mt: '100px', display: 'flex', justifyContent: 'center' }}>
          <CircularProgress />
        </Container>
        <Footer />
      </>
    )
  }

  if (error) {
    return (
      <>
        <Navbar />
        <Container sx={{ mt: '100px' }}>
          <Alert severity="error">{error}</Alert>
          <Button onClick={() => navigate('/dashboard')} sx={{ mt: 2 }}>
            Back to Dashboard
          </Button>
        </Container>
        <Footer />
      </>
    )
  }

  return (
    <>
      <Navbar />
      <Container sx={{ mt: '100px', mb: 4 }}>
        {/* Back Button */}
        <Button 
          startIcon={<ArrowBackIcon />}
          onClick={() => navigate('/dashboard')}
          sx={{ mb: 2 }}
        >
          Back to Dashboard
        </Button>

        {/* Project Header */}
        <Paper elevation={3} sx={{ p: 3, mb: 3, background: 'linear-gradient(135deg, #3874CB 0%, #2b5fa0 100%)', color: '#fff' }}>
          <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
            <Box>
              <Typography variant="h4" sx={{ fontWeight: 700, mb: 1 }}>
                {project?.name || 'Project'}
              </Typography>
              <Typography variant="body1" sx={{ mb: 2, opacity: 0.9 }}>
                {project?.description}
              </Typography>
            </Box>
            <Box sx={{ display: 'flex', gap: 1 }}>
              {isProjectAdmin && (
                <Button
                  variant="contained"
                  startIcon={<PersonAddIcon />}
                  onClick={handleOpenMemberDialog}
                  sx={{ 
                    bgcolor: 'rgba(255,255,255,0.2)', 
                    '&:hover': { bgcolor: 'rgba(255,255,255,0.3)' } 
                  }}
                >
                  Manage Members
                </Button>
              )}
              <Button
                variant="contained"
                startIcon={<AddIcon />}
                onClick={() => setCreateTaskOpen(true)}
                sx={{ 
                  bgcolor: 'rgba(255,255,255,0.2)', 
                  '&:hover': { bgcolor: 'rgba(255,255,255,0.3)' } 
                }}
              >
                Add Task
              </Button>
            </Box>
          </Box>

          <Divider sx={{ my: 1.5, bgcolor: 'rgba(255,255,255,0.2)' }} />

          <Box sx={{ display: 'flex', gap: 4, flexWrap: 'wrap' }}>
            <Box>
              <Typography variant="caption" sx={{ opacity: 0.7 }}>Created</Typography>
              <Typography variant="body2">
                {project?.createdAt?.substring(0, 10) || 'N/A'}
              </Typography>
            </Box>
            <Box>
              <Typography variant="caption" sx={{ opacity: 0.7 }}>Members</Typography>
              <Typography variant="body2">
                {project?.members?.length || 0} members
              </Typography>
            </Box>
            <Box>
              <Typography variant="caption" sx={{ opacity: 0.7 }}>Tasks</Typography>
              <Typography variant="body2">
                {tasks.length} total
              </Typography>
            </Box>
          </Box>

          {/* Members List */}
          <Box sx={{ mt: 2 }}>
            <Typography variant="caption" sx={{ opacity: 0.7, display: 'block', mb: 1 }}>
              Team Members
            </Typography>
            <Box sx={{ display: 'flex', gap: 1, flexWrap: 'wrap' }}>
              {project?.members?.map((member, index) => {
                const memberUser = typeof member.user === 'object' ? member.user : { _id: member.user, fullName: 'Unknown' }
                const isCurrentUser = memberUser._id === currentUser?._id
                
                return (
                  <Chip
                    key={index}
                    avatar={
                      <Avatar sx={{ width: 24, height: 24, fontSize: '0.8rem' }}>
                        {memberUser.fullName?.charAt(0) || 'U'}
                      </Avatar>
                    }
                    label={
                      <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.5 }}>
                        <span>{memberUser.fullName} ({member.role})</span>
                        {isCurrentUser && <span>(You)</span>}
                      </Box>
                    }
                    onDelete={
                      isProjectAdmin && member.role !== 'admin'
                        ? () => handleRemoveMember(memberUser._id)
                        : undefined
                    }
                    size="small"
                    sx={{ 
                      bgcolor: 'rgba(255,255,255,0.15)', 
                      color: '#fff',
                      '& .MuiChip-label': { fontSize: '0.8rem' },
                      '& .MuiChip-deleteIcon': {
                        color: 'rgba(255,255,255,0.7)',
                        '&:hover': { color: '#fff' }
                      }
                    }}
                  />
                )
              })}
            </Box>
            {isProjectAdmin && (
              <Typography variant="caption" sx={{ opacity: 0.5, display: 'block', mt: 1 }}>
                Click X on a member to remove them
              </Typography>
            )}
          </Box>
        </Paper>

        {/* Kanban Board */}
        <Grid container spacing={2}>
          <Grid size={{xs: 12, sm: 6, md: 3}}>
            <Paper sx={{ p: 1.5, bgcolor: '#e3f2fd', height: '100%', minHeight: 400 }}>
              <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 1.5 }}>
                <Typography variant="subtitle1" sx={{ fontWeight: 600, color: '#1976d2' }}>
                  📝 To Do
                </Typography>
                <Chip label={todoTasks.length} size="small" color="info" />
              </Box>
              <Box sx={{ maxHeight: 500, overflowY: 'auto', pr: 0.5 }}>
                {todoTasks.map(task => (
                  <TaskCard key={task._id} task={task} />
                ))}
                {todoTasks.length === 0 && (
                  <Typography variant="body2" color="text.secondary" sx={{ textAlign: 'center', mt: 4 }}>
                    No tasks
                  </Typography>
                )}
              </Box>
            </Paper>
          </Grid>

          <Grid size={{xs: 12, sm: 6, md: 3}}>
            <Paper sx={{ p: 1.5, bgcolor: '#fff3e0', height: '100%', minHeight: 400 }}>
              <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 1.5 }}>
                <Typography variant="subtitle1" sx={{ fontWeight: 600, color: '#f57c00' }}>
                  🔄 In Progress
                </Typography>
                <Chip label={inProgressTasks.length} size="small" color="warning" />
              </Box>
              <Box sx={{ maxHeight: 500, overflowY: 'auto', pr: 0.5 }}>
                {inProgressTasks.map(task => (
                  <TaskCard key={task._id} task={task} />
                ))}
                {inProgressTasks.length === 0 && (
                  <Typography variant="body2" color="text.secondary" sx={{ textAlign: 'center', mt: 4 }}>
                    No tasks
                  </Typography>
                )}
              </Box>
            </Paper>
          </Grid>

          <Grid size={{xs: 12, sm: 6, md: 3}}>
            <Paper sx={{ p: 1.5, bgcolor: '#f3e5f5', height: '100%', minHeight: 400 }}>
              <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 1.5 }}>
                <Typography variant="subtitle1" sx={{ fontWeight: 600, color: '#7b1fa2' }}>
                  👀 Review
                </Typography>
                <Chip label={reviewTasks.length} size="small" color="secondary" />
              </Box>
              <Box sx={{ maxHeight: 500, overflowY: 'auto', pr: 0.5 }}>
                {reviewTasks.map(task => (
                  <TaskCard key={task._id} task={task} />
                ))}
                {reviewTasks.length === 0 && (
                  <Typography variant="body2" color="text.secondary" sx={{ textAlign: 'center', mt: 4 }}>
                    No tasks
                  </Typography>
                )}
              </Box>
            </Paper>
          </Grid>

          <Grid size={{xs: 12, sm: 6, md: 3}}>
            <Paper sx={{ p: 1.5, bgcolor: '#e8f5e9', height: '100%', minHeight: 400 }}>
              <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 1.5 }}>
                <Typography variant="subtitle1" sx={{ fontWeight: 600, color: '#388e3c' }}>
                  ✅ Done
                </Typography>
                <Chip label={doneTasks.length} size="small" color="success" />
              </Box>
              <Box sx={{ maxHeight: 500, overflowY: 'auto', pr: 0.5 }}>
                {doneTasks.map(task => (
                  <TaskCard key={task._id} task={task} />
                ))}
                {doneTasks.length === 0 && (
                  <Typography variant="body2" color="text.secondary" sx={{ textAlign: 'center', mt: 4 }}>
                    No tasks
                  </Typography>
                )}
              </Box>
            </Paper>
          </Grid>
        </Grid>

        {/* Task Context Menu */}
        <Menu
          anchorEl={anchorEl}
          open={Boolean(anchorEl)}
          onClose={handleMenuClose}
        >
          <MenuItem onClick={() => handleStatusChange(menuTaskId, 'todo')}>Move to To Do</MenuItem>
          <MenuItem onClick={() => handleStatusChange(menuTaskId, 'in_progress')}>Move to In Progress</MenuItem>
          <MenuItem onClick={() => handleStatusChange(menuTaskId, 'review')}>Move to Review</MenuItem>
          <MenuItem onClick={() => handleStatusChange(menuTaskId, 'done')}>Move to Done</MenuItem>
          <Divider />
          <MenuItem onClick={() => handleDeleteTask(menuTaskId)}>
            <Typography color="error">Delete Task</Typography>
          </MenuItem>
        </Menu>

        {/* Task Detail Dialog */}
        <Dialog 
          open={taskDialogOpen} 
          onClose={() => setTaskDialogOpen(false)}
          maxWidth="sm"
          fullWidth
        >
          {selectedTask && (
            <>
              <DialogTitle>
                <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                  <Typography variant="h6">{selectedTask.title}</Typography>
                  <Chip 
                    label={selectedTask.status.replace('_', ' ')} 
                    color={getStatusColor(selectedTask.status)}
                    size="small"
                  />
                </Box>
              </DialogTitle>
              <DialogContent dividers>
                <Stack spacing={2}>
                  <Box>
                    <Typography variant="subtitle2" color="text.secondary">Description</Typography>
                    <Typography variant="body2">
                      {selectedTask.description || 'No description provided'}
                    </Typography>
                  </Box>
                  
                  <Grid container spacing={2}>
                    <Grid size={6}>
                      <Typography variant="subtitle2" color="text.secondary">Priority</Typography>
                      <Chip 
                        label={selectedTask.priority} 
                        color={getPriorityColor(selectedTask.priority)}
                        size="small"
                      />
                    </Grid>
                    <Grid size={6}>
                      <Typography variant="subtitle2" color="text.secondary">Due Date</Typography>
                      <Typography variant="body2">
                        {selectedTask.dueDate 
                          ? new Date(selectedTask.dueDate).toLocaleDateString('en-US', {
                              month: 'long',
                              day: 'numeric',
                              year: 'numeric'
                            })
                          : 'No due date'
                        }
                      </Typography>
                    </Grid>
                  </Grid>

                  <Box>
                    <Typography variant="subtitle2" color="text.secondary">Assigned To</Typography>
                    <Typography variant="body2">
                      {typeof selectedTask.assignedTo === 'object' 
                        ? selectedTask.assignedTo.fullName 
                        : 'Unassigned'}
                    </Typography>
                  </Box>

                  <Box>
                    <Typography variant="subtitle2" color="text.secondary">Created</Typography>
                    <Typography variant="body2">
                      {new Date(selectedTask.createdAt).toLocaleDateString('en-US', {
                        month: 'long',
                        day: 'numeric',
                        year: 'numeric'
                      })}
                    </Typography>
                  </Box>
                </Stack>
              </DialogContent>
              <DialogActions>
                <Button onClick={() => setTaskDialogOpen(false)}>Close</Button>
              </DialogActions>
            </>
          )}
        </Dialog>

        {/* Create Task Dialog */}
        <Dialog 
          open={createTaskOpen} 
          onClose={() => setCreateTaskOpen(false)}
          maxWidth="sm"
          fullWidth
        >
          <DialogTitle>Create New Task</DialogTitle>
          <DialogContent>
            <Stack spacing={2} sx={{ mt: 1 }}>
              <TextField
                label="Task Title"
                fullWidth
                required
                value={newTask.title}
                onChange={(e) => setNewTask({...newTask, title: e.target.value})}
              />
              <TextField
                label="Description"
                fullWidth
                multiline
                rows={3}
                value={newTask.description}
                onChange={(e) => setNewTask({...newTask, description: e.target.value})}
              />
              <FormControl fullWidth>
                <InputLabel>Priority</InputLabel>
                <Select
                  value={newTask.priority}
                  label="Priority"
                  onChange={(e) => setNewTask({...newTask, priority: e.target.value})}
                >
                  <MenuItem value="low">Low</MenuItem>
                  <MenuItem value="medium">Medium</MenuItem>
                  <MenuItem value="high">High</MenuItem>
                </Select>
              </FormControl>
              <TextField
                label="Due Date"
                type="date"
                fullWidth
                InputLabelProps={{ shrink: true }}
                value={newTask.dueDate}
                onChange={(e) => setNewTask({...newTask, dueDate: e.target.value})}
              />
              <FormControl fullWidth>
                <InputLabel>Assign To</InputLabel>
                <Select
                  value={newTask.assignedTo}
                  label="Assign To"
                  onChange={(e) => setNewTask({...newTask, assignedTo: e.target.value})}
                >
                  <MenuItem value="">Unassigned</MenuItem>
                  {project?.members?.map((member, index) => {
                    const memberUser = typeof member.user === 'object' ? member.user : { _id: member.user }
                    return (
                      <MenuItem key={index} value={memberUser._id}>
                        {memberUser.fullName || `Member ${index + 1}`}
                      </MenuItem>
                    )
                  })}
                </Select>
              </FormControl>
            </Stack>
          </DialogContent>
          <DialogActions>
            <Button onClick={() => setCreateTaskOpen(false)}>Cancel</Button>
            <Button 
              variant="contained" 
              onClick={handleCreateTask}
              disabled={!newTask.title}
            >
              Create Task
            </Button>
          </DialogActions>
        </Dialog>

        {/* Member Management Dialog */}
        <Dialog 
          open={memberDialogOpen} 
          onClose={() => setMemberDialogOpen(false)}
          maxWidth="sm"
          fullWidth
        >
          <DialogTitle>Manage Members</DialogTitle>
          <DialogContent>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
              Current Members:
            </Typography>
            <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 1, mb: 3 }}>
              {project?.members?.map((member, index) => {
                const memberUser = typeof member.user === 'object' ? member.user : { _id: member.user, fullName: 'Unknown' }
                return (
                  <Chip
                    key={index}
                    label={`${memberUser.fullName} (${member.role})`}
                    onDelete={
                      member.role !== 'admin' 
                        ? () => handleRemoveMember(memberUser._id)
                        : undefined
                    }
                    color={member.role === 'admin' ? 'primary' : 'default'}
                  />
                )
              })}
            </Box>
            
            <Divider sx={{ my: 2 }} />
            
            <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
              Add New Members:
            </Typography>
            <FormControl fullWidth>
              <InputLabel>Select Users</InputLabel>
              <Select
                multiple
                value={selectedUsers}
                onChange={(e) => setSelectedUsers(e.target.value)}
                input={<OutlinedInput label="Select Users" />}
                renderValue={(selected) => (
                  <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 0.5 }}>
                    {selected.map((userId) => {
                      const user = availableUsers.find(u => u._id === userId)
                      return (
                        <Chip 
                          key={userId} 
                          label={user?.fullName || userId} 
                          size="small"
                        />
                      )
                    })}
                  </Box>
                )}
              >
                {availableUsers
                  .filter(u => !project?.members?.some(m => 
                    (typeof m.user === 'object' ? m.user._id : m.user) === u._id
                  ))
                  .map((user) => (
                    <MenuItem key={user._id} value={user._id}>
                      {user.fullName} ({user.email})
                    </MenuItem>
                  ))
                }
              </Select>
            </FormControl>
          </DialogContent>
          <DialogActions>
            <Button onClick={() => setMemberDialogOpen(false)}>Close</Button>
            <Button 
              variant="contained" 
              onClick={handleAddMembers}
              disabled={selectedUsers.length === 0}
            >
              Add Selected Members
            </Button>
          </DialogActions>
        </Dialog>

        {/* Snackbar for notifications */}
        <Snackbar
          open={snackbar.open}
          autoHideDuration={4000}
          onClose={() => setSnackbar({ ...snackbar, open: false })}
        >
          <Alert 
            onClose={() => setSnackbar({ ...snackbar, open: false })} 
            severity={snackbar.severity}
          >
            {snackbar.message}
          </Alert>
        </Snackbar>
      </Container>
      <Footer />
    </>
  )
}

export default Project