import { lazy, Suspense } from 'react'
import {
  BrowserRouter as Router,
  Routes,
  Route,
  Navigate
} from 'react-router-dom'
import { CircularProgress } from '@mui/material'
import { useSelector } from 'react-redux'
import Project from './pages/Project'

const Login = lazy(() => import('./pages/Login'))
const Dashboard = lazy(() => import('./pages/Dashboard'))
const SignUp = lazy(() => import('./pages/SignUp'))

const App = () => {
  const { currentUser } = useSelector(state => state.user)

  return (
    <Router>
      <Suspense fallback={
        <CircularProgress />
      }>
        <Routes>
          <Route path='/' element={currentUser ? <Navigate to='/dashboard' /> : <Login />} />
          <Route path='/dashboard' element={currentUser ? <Dashboard /> : <Navigate to='/' />} />
          <Route path='/register' element={currentUser ? <Navigate to='/dashboard' /> : <SignUp /> } />
          <Route path='/projects/:id' element={currentUser ? <Project /> : <Navigate to='/' />} />
        </Routes>
      </Suspense>
    </Router>
  )
}

export default App
